parameters.jsCode:
const item = $input.item;
const body = item.json.body || item.json;

let raw = {};
try {
  raw = JSON.parse(body.rawRequest || '{}');
} catch (error) {
  raw = {};
}

const publicBaseUrl = 'https://images.rocksolidleveling.com';
const splitFullName = (value) => {
  const trimmed = String(value || '').trim();
  if (!trimmed) return { firstName: '', lastName: '' };
  const [firstName, ...rest] = trimmed.split(/\s+/);
  return { firstName, lastName: rest.join(' ') };
};
const slugify = (value, fallback = 'file') => {
  const cleaned = String(value || fallback)
    .toLowerCase()
    .replace(/[^a-z0-9.-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);

  return cleaned || fallback;
};

const suppliedFirst = String(body.firstName || raw.q11_name?.first || '').trim();
const suppliedLast = String(body.lastName || raw.q11_name?.last || '').trim();
const suppliedFullName = String(body.fullName || '').trim();
const nameParts = suppliedFirst || suppliedLast
  ? { firstName: suppliedFirst, lastName: suppliedLast }
  : splitFullName(suppliedFullName);

const submissionId = String(body.submissionID || body.submissionId || `rsl-${Date.now()}`);
const submissionSlug = slugify(submissionId, `submission-${Date.now()}`);
const now = new Date();
const year = String(now.getUTCFullYear());
const month = String(now.getUTCMonth() + 1).padStart(2, '0');
const day = String(now.getUTCDate()).padStart(2, '0');
const datePath = `${year}/${month}/${day}`;
const binaryEntries = Object.entries(item.binary || {});

const uploads = binaryEntries.map(([binaryKey, file], index) => {
  const originalName = file.fileName || `upload-${index + 1}`;
  const extensionMatch = originalName.match(/\.[A-Za-z0-9]+$/);
  const extension = extensionMatch ? extensionMatch[0].toLowerCase() : '';
  const baseName = extension ? originalName.slice(0, -extension.length) : originalName;
  const safeFileName = `${String(index + 1).padStart(2, '0')}-${slugify(baseName, `upload-${index + 1}`)}${extension}`;
  const objectKey = `website-quotes/${datePath}/${submissionSlug}/${safeFileName}`;

  return {
    binaryKey,
    fileName: safeFileName,
    objectKey,
    publicUrl: `${publicBaseUrl}/${objectKey}`
  };
});

return {
  json: {
    contact: {
      firstName: nameParts.firstName,
      lastName: nameParts.lastName,
      email: String(body.email || raw.q5_email5 || '').trim(),
      phone: String(body.phone || raw.q12_phoneNumber?.full || '').trim(),
      address1: String(body.address || '').trim(),
      city: '',
      state: '',
      postalCode: '',
      country: 'United States',
      squareFeetOfSlabs: String(body.squareFeet || raw.q13_number || '').trim(),
      notes: String(body.details || raw.q17_anyNotes || '').trim(),
      formId: String(body.formID || '').trim(),
      submissionId,
      imageCount: uploads.length,
      fileUploads: [],
      imageUrlsText: ''
    },
    uploads
  },
  binary: item.binary
};

const item = $input.item;
const upload = item.json.upload ?? item.json.uploads ?? (item.json.binaryKey ? {
  binaryKey: item.json.binaryKey,
  fileName: item.json.fileName,
  objectKey: item.json.objectKey,
  publicUrl: item.json.publicUrl,
} : undefined);

if (!upload) {
  throw new Error(`Could not find upload data on the split item. Available keys: ${Object.keys(item.json || {}).join(', ')}`);
}

const sourceBinary = item.binary?.[upload.binaryKey];

if (!sourceBinary) {
  throw new Error(`Missing binary data for upload key: ${upload.binaryKey}. Available binary keys: ${Object.keys(item.binary || {}).join(', ')}`);
}

return {
  json: {
    contact: item.json.contact,
    upload
  },
  binary: {
    data: {
      ...sourceBinary,
      fileName: upload.fileName
    }
  }
};

const item = $input.item;
const urls = Array.isArray(item.json.publicUrl)
  ? item.json.publicUrl.filter(Boolean)
  : [];

return {
  json: {
    contact: {
      ...item.json.contact,
      fileUploads: urls,
      imageUrlsText: urls.join('\n')
    }
  }
};

const item = $input.item;

return {
  json: {
    contact: {
      ...item.json.contact,
      fileUploads: [],
      imageUrlsText: ''
    }
  }
};

